# File: sensor.py
import Adafruit_DHT

def initialize_dht(pin=4):
 """Initialize DHT22 sensor on specified GPIO pin"""
 return Adafruit_DHT.DHT22(pin)

def read_temperature(sensor):
 """Read temperature value from sensor"""
 humidity, temp = Adafruit_DHT.read_retry(sensor)
 return temp
